SELECT p.id, p.sku, p.product_name AS productName, p.product_name_en AS productNameEn, p.category_id AS categoryId, c.category_name AS categoryNameCn, c.category_name_en AS categoryNameEn, p.description, p.specification, p.material, p.color, p.size, p.weight, p.length, p.width, p.height, p.cost_price AS costPrice, p.factory_price AS factoryPrice, p.fob_price AS fobPrice, p.cif_price AS cifPrice, p.min_order_qty AS minOrderQty, p.stock_qty AS stockQty, p.main_image AS mainImage, p.images, p.video_url AS videoUrl, p.status, p.hs_code AS hsCode, p.tax_refund_rate AS taxRefundRate, p.created_by AS createdBy, p.created_time AS createdTime, p.updated_by AS updatedBy, p.updated_time AS updatedTime, p.remark FROM crm_product p LEFT JOIN crm_product_category c ON p.category_id = c.id AND c.deleted = 0 WHERE p.deleted = 0
AND (p.product_name LIKE CONCAT('%', #{query.productName}, '%') OR p.product_name_en LIKE CONCAT('%', #{query.productName}, '%'))
AND p.sku LIKE CONCAT('%', #{query.sku}, '%')
AND p.category_id = #{query.categoryId}
AND p.status = #{query.status}
AND p.hs_code = #{query.hsCode}
AND p.fob_price >= #{query.minPrice}
AND p.fob_price <= #{query.maxPrice}
AND p.stock_qty > 0
AND p.stock_qty = 0
ORDER BY p.created_time DESC

SELECT p.id, p.sku, p.product_name AS productName, p.product_name_en AS productNameEn, c.category_name AS categoryNameCn, c.category_name_en AS categoryNameEn, p.description, p.specification, p.cost_price AS costPrice, p.factory_price AS factoryPrice, p.fob_price AS fobPrice, p.cif_price AS cifPrice, p.min_order_qty AS minOrderQty, p.stock_qty AS stockQty, p.main_image AS mainImage, p.status, p.hs_code AS hsCode, p.tax_refund_rate AS taxRefundRate, p.created_time AS createdTime, p.remark FROM crm_product p LEFT JOIN crm_product_category c ON p.category_id = c.id AND c.deleted = 0 WHERE p.deleted = 0
AND (p.product_name LIKE CONCAT('%', #{query.productName}, '%') OR p.product_name_en LIKE CONCAT('%', #{query.productName}, '%'))
AND p.sku LIKE CONCAT('%', #{query.sku}, '%')
AND p.category_id = #{query.categoryId}
AND p.status = #{query.status}
ORDER BY p.created_time DESC
